import { defineComponentStyle } from "@yamada-ui/react"

export const imageStyle = defineComponentStyle({})

export type ImageStyle = typeof imageStyle

import { a11y, page, render } from "#test/browser"
import { Image } from "./image"

const src = "https://image.xyz/source"

describe("<Image />", () => {
  test("renders component correctly", async () => {
    await a11y(<Image src={src} alt="image" />)
  })

  test("sets `displayName` correctly", () => {
    expect(Image.displayName).toBe("Image")
  })

  test("sets `className` correctly", async () => {
    await render(<Image src={src} />)

    await expect.element(page.getByRole("img")).toHaveClass("ui-image")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Image src={src} />)

    const img = page.getByRole("img").element()

    expect(img).toBeInstanceOf(HTMLImageElement)
  })

  test("renders image if there is no fallback behavior defined", async () => {
    await render(<Image src={src} />)

    await expect.element(page.getByRole("img")).toHaveAttribute("src", src)
  })
})

"use client"

import type { CSSProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { ImageStyle } from "./image.style"
import { createComponent } from "@yamada-ui/react"
import { imageStyle } from "./image.style"

export interface ImageProps
  extends HTMLStyledProps<"img">, ThemeProps<ImageStyle> {
  /**
   * The CSS `object-fit` property.
   */
  fit?: CSSProps["objectFit"]
}

const {
  PropsContext: ImagePropsContext,
  usePropsContext: useImagePropsContext,
  withContext,
} = createComponent<ImageProps, ImageStyle>("image", imageStyle)

export { ImagePropsContext, useImagePropsContext }

/**
 * `Image` is a component that displays images with fallback support.
 *
 * @see https://yamada-ui.com/docs/components/image
 */
export const Image = withContext("img")(undefined, ({ fit, ...rest }) => ({
  objectFit: fit,
  ...rest,
}))
